// n8n 的 Code 节点里，items 代表传进来的所有数据
// 因为 Loop Over Items 的 Batch Size = 1，所以通常这里一次只有 1 条 item
return items.map(item => {
  // item.json 就是当前这条数据的具体内容
  const j = item.json;

  // 这个函数的作用：
  // 把任何类型的值都转换成字符串
  // 因为 Notion 里面有些字段可能是空值、数组、对象
  // 后面 AI Prompt 需要的是普通文字，所以要统一转成字符串
  function toStr(value) {
    if (value === undefined || value === null) return "";
    if (Array.isArray(value)) return value.join("\n");
    if (typeof value === "object") return JSON.stringify(value);
    return String(value).trim();
  }

  // 这个函数的作用：
  // 从多个可能的字段名里，找到第一个有内容的字段
  //
  // 例如你的字段可能叫：
  // Pain Point Summary
  // pain_point_summary
  // 痛点总结
  //
  // 它会按顺序找，只要找到有内容的，就返回这个内容
  function pick(keys) {
    for (const key of keys) {
      const value = j[key];
      const str = toStr(value);
      if (str) return str;
    }
    return "";
  }

  // 获取 Notion 页面 ID
  // 后面的 Notion Update 要靠这个 ID 知道“更新哪一页”
  const notionPageId = j.id || j.page_id || j.notion_page_id || "";

  // 获取痛点总结
  const painPoint = pick([
    "property_pain_point_summary",
    "Pain Point Summary",
    "pain_point_summary",
    "痛点总结",
    "痛点",
    "Pain Point"
  ]);

  // 获取 Hook 标题
  const hook = pick([
    "property_hook",
    "property_name",
    "Hook",
    "hook",
    "爆款HOOK标题",
    "爆款 Hook",
    "Name",
    "Title"
  ]);

  // 获取分类
  const category = pick([
    "property_category",
    "Category",
    "category",
    "分类"
  ]);

  // 获取情绪
  const emotion = pick([
    "property_emotion",
    "Emotion",
    "emotion",
    "情绪"
  ]);

  // 获取 Reddit 原帖标题
  const originalTitle = pick([
    "property_original_title",
    "property_name",
    "Original Title",
    "original_title",
    "Reddit Title",
    "原帖标题",
    "Title",
    "Name"
  ]);

  // 获取 Reddit 原帖正文
  const originalText = pick([
    "property_original_text",
    "property_evidence",
    "Original Text",
    "original_text",
    "Reddit Text",
    "原帖正文",
    "正文",
    "Content"
  ]);

  // 获取原帖链接
  const sourceUrl = pick([
    "property_source_url",
    "Source URL",
    "source_url",
    "URL",
    "link",
    "原帖链接"
  ]);

  // 把几个重要字段合并到一起
  // 后面用来识别这条内容可能涉及哪个城市或主题
  const combinedText = [
    painPoint,
    hook,
    category,
    originalTitle,
    originalText
  ].join(" ");

  // 识别是否提到了中国具体城市或区域
  // 这个不是为了限制账号方向，而是为了让搜索更精准
  //
  // 例如：
  // 如果原帖提到 Shanghai，就搜索上海相关解决方案
  // 如果提到 Beijing，就搜索北京相关解决方案
  // 如果没有具体城市，就搜索中国通用解决方案
  const cityKeywords = [
    "Beijing", "北京",
    "Shanghai", "上海",
    "Guangzhou", "广州",
    "Shenzhen", "深圳",
    "Chengdu", "成都",
    "Chongqing", "重庆",
    "Xi'an", "Xian", "西安",
    "Hangzhou", "杭州",
    "Suzhou", "苏州",
    "Nanjing", "南京",
    "Guilin", "桂林",
    "Zhangjiajie", "张家界",
    "Yunnan", "云南",
    "Dali", "大理",
    "Lijiang", "丽江",
    "Kunming", "昆明",
    "Tibet", "西藏",
    "Xinjiang", "新疆",
    "Sichuan", "四川",
    "Gansu", "甘肃",
    "Qinghai", "青海",
    "Harbin", "哈尔滨",
    "Hainan", "海南",
    "Sanya", "三亚",
    "Hong Kong", "香港",
    "Macau", "澳门"
  ];

  // 从 combinedText 里找出出现过的城市/区域关键词
  const matchedCities = cityKeywords.filter(city => {
    return combinedText.toLowerCase().includes(city.toLowerCase());
  });

  // 去重，避免同一个城市重复出现
  const uniqueCities = [...new Set(matchedCities)];

  // 判断内容主题
  // 这里不是严格分类，只是为了辅助生成更好的 research query
  const isPaymentRelated = /alipay|wechat pay|payment|pay|card|visa card|mastercard|支付宝|微信支付|支付|银行卡|信用卡/i.test(combinedText);

  const isTransportRelated = /train|railway|high speed rail|metro|subway|taxi|didi|airport|transport|bus|交通|高铁|火车|地铁|机场|打车|滴滴|巴士/i.test(combinedText);

  const isVisaRelated = /visa|entry|144|240|transit|passport|immigration|免签|签证|入境|过境|护照/i.test(combinedText);

  const isFoodRelated = /food|restaurant|spicy|vegetarian|halal|menu|eat|hotpot|美食|餐厅|吃|火锅|不辣|素食|清真/i.test(combinedText);

  const isAppRelated = /app|vpn|esim|sim|map|translate|wechat|alipay|didi|ctrip|trip.com|应用|软件|地图|翻译|电话卡/i.test(combinedText);

  const isCultureExperienceRelated = /culture|temple|museum|tea|kung fu|opera|tcm|massage|calligraphy|文化|寺庙|博物馆|茶|功夫|戏曲|中医|推拿|书法/i.test(combinedText);

  // 根据识别到的主题，生成搜索方向
  const topicHints = [];

  if (isPaymentRelated) {
    topicHints.push("mobile payment setup for foreign visitors in China");
  }

  if (isTransportRelated) {
    topicHints.push("China transportation tips for foreign tourists");
  }

  if (isVisaRelated) {
    topicHints.push("China visa-free transit and entry rules for foreign travelers");
  }

  if (isFoodRelated) {
    topicHints.push("China food ordering and restaurant tips for foreign tourists");
  }

  if (isAppRelated) {
    topicHints.push("essential apps for traveling in China as a foreigner");
  }

  if (isCultureExperienceRelated) {
    topicHints.push("authentic Chinese cultural experiences for foreign visitors");
  }

  // 如果没有识别出具体主题，就使用通用入境游方向
  if (topicHints.length === 0) {
    topicHints.push("China inbound travel practical tips for foreign visitors");
  }

  // 如果原文提到城市，就把城市加入搜索词
  // 如果没有提到城市，就保持中国通用方向
  const locationHint = uniqueCities.length > 0
    ? uniqueCities.join(" ")
    : "China";

  // 最终生成 research query
  //
  // 这个 query 会给 AI Agent 作为“搜索建议”
  // Agent 仍然可以根据任务自己调整搜索词
  const researchQuery = [
    painPoint,
    category,
    locationHint,
    topicHints.join(" "),
    "foreign tourists",
    "practical solution",
    "official source or recent reliable guide",
    "latest information"
  ]
    .filter(Boolean)
    .join(" ");

  // 返回整理后的数据
  return {
    json: {
      // 保留 Notion 原始输出
      ...j,

      // Notion 页面 ID
      notion_page_id: notionPageId,

      // 标准化后的痛点总结
      pain_point_summary_clean: painPoint.slice(0, 2000),

      // 标准化后的 Hook
      hook_clean: hook,

      // 标准化后的分类
      category_clean: category,

      // 标准化后的情绪
      emotion_clean: emotion,

      // 标准化后的 Reddit 标题
      original_title_clean: originalTitle,

      // 标准化后的 Reddit 正文
      original_text_clean: originalText.slice(0, 5000),

      // 标准化后的原帖链接
      source_url_clean: sourceUrl,

      // 是否识别到了具体城市/区域
      matched_locations: uniqueCities.join(", "),

      // 识别出来的主题方向
      topic_hints: topicHints.join("; "),

      // 给 AI Agent 的搜索建议
      research_query: researchQuery
    }
  };
});

const base = $('Normalize Engine1 Notion Item').item.json;
let ai = $input.first().json;

function cleanJsonString(str) {
  return String(str)
    .replace(/^```json/i, "")
    .replace(/^```/i, "")
    .replace(/```$/i, "")
    .trim();
}

if (ai.output) {
  if (typeof ai.output === "string") {
    try {
      ai = JSON.parse(cleanJsonString(ai.output));
    } catch (error) {
      ai = {
        research_status: "needs_manual_check",
        confidence: "low",
        solution_summary: "",
        step_by_step_solution: [],
        common_mistakes: [],
        local_chengdu_angle: "",
        source_links: [],
        missing_info: "AI Agent output could not be parsed as JSON.",
        draft_angle: "",
        image_brief: "",
        claim_check_notes: String(error.message || error)
      };
    }
  } else if (typeof ai.output === "object") {
    ai = ai.output;
  }
}

const stepByStep = Array.isArray(ai.step_by_step_solution) ? ai.step_by_step_solution : [];
const mistakes = Array.isArray(ai.common_mistakes) ? ai.common_mistakes : [];
const links = Array.isArray(ai.source_links) ? ai.source_links : [];

const sourceLinksText = links.map((s, index) => {
  return [
    `${index + 1}. ${s.title || "Untitled source"}`,
    `URL: ${s.url || ""}`,
    `Type: ${s.source_type || "other"}`,
    `Why useful: ${s.why_useful || ""}`
  ].join("\n");
}).join("\n\n");

const finalStatus =
  ai.research_status === "solved" && ai.confidence !== "low"
    ? "📝 To Draft"
    : "🧐 Needs Manual Check";

return [
  {
    json: {
      ...base,
      ...ai,
      step_by_step_solution_text: stepByStep.map((s, i) => `${i + 1}. ${s}`).join("\n"),
      common_mistakes_text: mistakes.map((s, i) => `${i + 1}. ${s}`).join("\n"),
      source_links_text: sourceLinksText,
      final_status: finalStatus
    }
  }
];
